record.field:
# ========== Step 1: Delete Demo Applicants ==========
demo_applicants = env['hr.applicant'].search([
    '|', ('recruitment_type', '=', False),
    ('recruitment_type', '=', None)
])
demo_count = len(demo_applicants)
if demo_applicants:
    demo_applicants.unlink()

# ========== Step 2: Find Default Odoo Stages (by NAME) ==========
# Xác định các default stage names của Odoo
default_odoo_stage_names = [
    'New', 'Qualification', 'First Interview', 'Second Interview',
    'Contract Proposal', 'Contract Signed', 'Refused'
]

old_stages = env['hr.recruitment.stage'].search([
    ('name', 'in', default_odoo_stage_names)
])

if not old_stages:
    action = {
        'type': 'ir.actions.client',
        'tag': 'display_notification',
        'params': {
            'title': 'Done!',
            'message': f'Deleted {demo_count} demo applicants. No old stages found.',
            'type': 'success',
        }
    }
else:
    # ========== Step 3: Migrate Applicants from Old Stages ==========
    applicants_in_limbo = env['hr.applicant'].search([
        ('stage_id', 'in', old_stages.ids),
        ('recruitment_type', '!=', False)
    ])

    migrated_count = 0
    for app in applicants_in_limbo:
        new_stage = env['hr.recruitment.stage'].search([
            ('recruitment_type', '=', app.recruitment_type)
        ], order='sequence asc', limit=1)

        if new_stage:
            app.write({'stage_id': new_stage.id})
            migrated_count += 1

    # ========== Step 4: DELETE Old Stages ==========
    stage_count = len(old_stages)
    try:
        old_stages.unlink()
        deleted = True
    except Exception as e:
        deleted = False
        error_msg = str(e)

    # ========== Result Message ==========
    if deleted:
        action = {
            'type': 'ir.actions.client',
            'tag': 'display_notification',
            'params': {
                'title': 'Success!',
                'message': f'✅ Deleted {demo_count} demo applicants\n✅ Migrated {migrated_count} applicants\n✅ DELETED {stage_count} old stages',
                'type': 'success',
                'sticky': True,
            }
        }
    else:
        action = {
            'type': 'ir.actions.client',
            'tag': 'display_notification',
            'params': {
                'title': 'Partial Success',
                'message': f'✅ Deleted {demo_count} demo applicants\n✅ Migrated {migrated_count} applicants\n⚠️ Could not delete stages: {error_msg[:100]}',
                'type': 'warning',
                'sticky': True,
            }
        }
